            throw new Error('Command output exceeded buffer limit');
        }

        // Re-throw validation errors
        if (error.message.includes('must be') || 
            error.message.includes('does not exist') || 
            error.message.includes('is not a directory')) {
            throw error;
        }

        // For other execution errors, wrap in a more descriptive error
        throw new Error(`Failed to analyze sudo usage: ${error.message}`);
    }
}

// Export the function as specified
module.exports = { analyzeSudoUsageInScripts };
